type DomainId = "overview" | "projects" | "equipment" | "models" | "cables" | "catalog" | "documents" | "movement" | "inventory" | "people" | "contractors" | "finance" | "problems" | "reports" | "permissions" | "audit";
interface WorkspaceTab { id: string; domain: DomainId; title: string; entityId?: string; dirty?: boolean }

const domains: Array<{ id: DomainId; label: string; group: string; hint: string }> = [
  { id: "overview", label: "Обзор", group: "Контроль", hint: "Проблемы и показатели" },
  { id: "projects", label: "Проекты", group: "Планирование", hint: "Реестр и карточки" },
  { id: "equipment", label: "Оборудование", group: "Справочники", hint: "Модели и единицы" },
  { id: "models", label: "Модели", group: "Справочники", hint: "Характеристики и комплектность" },
  { id: "cables", label: "Кабели и комплектующие", group: "Справочники", hint: "Разъёмы, питание, остатки и выдача" },
  { id: "catalog", label: "Расходники и комплекты", group: "Справочники", hint: "Расходные материалы и состав комплектов" },
  { id: "documents", label: "Выдача и возврат", group: "Документы", hint: "Операции со склада" },
  { id: "inventory", label: "Инвентаризация", group: "Документы", hint: "Ожидалось и найдено" },
  { id: "movement", label: "Движение", group: "Отчёты", hint: "Неизменяемый журнал" },
  { id: "people", label: "Люди", group: "Управление", hint: "Сотрудники и роли" },
  { id: "contractors", label: "Подрядчики", group: "Управление", hint: "Передачи и долги" },
  { id: "finance", label: "Финансы", group: "Управление", hint: "Счета и транзакции" },
  { id: "problems", label: "Проблемы", group: "Контроль", hint: "Исключения и решения" },
  { id: "reports", label: "Конструктор отчётов", group: "Отчёты", hint: "Группировка показателей" },
  { id: "permissions", label: "Права доступа", group: "Администрирование", hint: "Матрица ролей" },
  { id: "audit", label: "Журнал действий", group: "Администрирование", hint: "Кто и что изменил" },
];

const statusLabel: Record<string, string> = { in_stock: "На складе", reserved: "Зарезервировано", on_project: "На проекте", in_repair: "В ремонте", at_contractor: "У подрядчика", lost: "Утеряно", draft: "Черновик", confirmed: "Подтверждён", in_progress: "В работе", completed: "Завершён", cancelled: "Отменён" };
const catalogKindLabel: Record<Catalog.CatalogItemKind, string> = { product: "Расходный материал", item: "Складская позиция", semi_finished: "Сборочная заготовка", modifier: "Дополнение", equipment_kit: "Комплект" };
const catalogUnitLabel: Record<string, string> = { pcs: "шт.", roll: "рулон", kit: "комплект", m: "м", kg: "кг", l: "л" };
const storageZoneKindLabel:Record<Equipment.StorageZoneKind,string>={room:"Помещение",rack:"Стеллаж",shelf:"Полка",bin:"Ячейка",floor:"Напольная зона",other:"Другое"};
const dt = (value: string | null | undefined) => value ? new Date(value).toLocaleString("ru-RU") : "—";
const money = (value: number) => new Intl.NumberFormat("ru-RU", { style: "currency", currency: "EUR" }).format(value);
function domainAllowed(domain: DomainId, can: (...permissions: Permission[]) => boolean) {
  if (["equipment","models","cables","catalog","documents","inventory","movement","problems","reports"].includes(domain)) return can("warehouse.view");
  if (domain === "projects") return can("projects.view");
  if (domain === "people" || domain === "permissions") return can("people.view", "people.manage", "roles.manage");
  if (domain === "audit") return can("roles.manage");
  if (domain === "contractors") return can("projects.reservation.manage", "finance.view");
  if (domain === "finance") return can("finance.view");
  return true;
}

export function BackofficePage() {
  const navigate = useNavigate();
  const [params, setParams] = useSearchParams();
  const { user, can } = useSession();
  const { view, selectView } = useBackofficeAppearance(user?.id);
  const { theme, toggle: toggleTheme } = useTheme();
  const data = useBackofficeData(can);
  const commands = useBackofficeCommands();
  const initialDomain = domains.some((item) => item.id === params.get("domain")) ? params.get("domain") as DomainId : "overview";
  const initialEntityId = params.get("id") ?? undefined;
  const initialTabId = initialEntityId ? `${initialDomain}:${initialEntityId}` : initialDomain;
  const [tabs, setTabs] = useState<WorkspaceTab[]>([{ id: initialTabId, domain: initialDomain, entityId: initialEntityId, title: domains.find((d) => d.id === initialDomain)?.label ?? "Обзор" }]);
  const [activeTab, setActiveTab] = useState(initialTabId);
  const [globalQuery, setGlobalQuery] = useState("");
  const [warehouseId, setWarehouseId] = useState("all");
  const active = tabs.find((tab) => tab.id === activeTab) ?? tabs[0]!;

  const openDomain = (domain: DomainId, entityId?: string, title?: string) => {
    const id = entityId ? `${domain}:${entityId}` : domain;
    setTabs((current) => current.some((tab) => tab.id === id) ? current : [...current, { id, domain, entityId, title: title ?? domains.find((item) => item.id === domain)?.label ?? domain }]);
    setActiveTab(id);
    setParams({ domain, ...(entityId ? { id: entityId } : {}) });
  };
  const closeTab = (id: string) => {
    if (id === "overview") return;
    const next = tabs.filter((tab) => tab.id !== id);
    setTabs(next);
    if (activeTab === id) { setActiveTab(next.at(-1)?.id ?? "overview"); setParams({ domain: next.at(-1)?.domain ?? "overview" }); }
  };
  const grouped = useMemo(() => domains.filter((item) => domainAllowed(item.id, can)).reduce<Record<string, typeof domains>>((acc, item) => ({ ...acc, [item.group]: [...(acc[item.group] ?? []), item] }), {}), [can]);

  return <div className="bo-shell" data-bo-view={view}>
    <aside className="bo-sidebar">
      <button className="bo-brand" onClick={() => navigate("/apex")}><BrandLogo size={30} color="var(--text)" /><span><strong>SEVER</strong><small>Backoffice</small></span></button>
      <nav className="bo-nav" aria-label="Разделы Backoffice">{Object.entries(grouped).map(([group, items]) => <div className="bo-nav__group" key={group}><div className="bo-nav__group-label">{group}</div>{items.map((item) => <button key={item.id} className={`bo-nav__item ${active.domain === item.id ? "bo-nav__item--active" : ""}`} onClick={() => openDomain(item.id)}><span>{item.label}</span><small>{item.hint}</small></button>)}</div>)}</nav>
    </aside>
    <section className="bo-main">
      <header className="bo-topbar"><div><div className="bo-eyebrow">SEVER · рабочий контур</div><h1>{domains.find((item) => item.id === active.domain)?.label}</h1></div><div className="bo-topbar__actions">
        <select aria-label="Склад" value={warehouseId} onChange={(event) => setWarehouseId(event.target.value)}><option value="all">Все склады</option>{(data.warehouses.data ?? []).map((warehouse) => <option key={warehouse.id} value={warehouse.id}>{warehouse.name}</option>)}</select>
        <input className="bo-command" aria-label="Глобальный поиск" value={globalQuery} onChange={(event) => setGlobalQuery(event.target.value)} placeholder="Поиск записей, документов, кодов" />
        <button className="bo-icon-button" onClick={() => navigate("/apex")}>Мобильный режим</button>
        <details className="bo-user-menu"><summary className="bo-user">{user?.displayName ?? "SEVER user"}</summary><div className="bo-user-menu__popover"><div className="bo-user-menu__title">Вид Backoffice</div><div className="bo-user-menu__label">Оформление</div><div className="bo-view-switch" aria-label="Оформление Backoffice"><button className={view === "classic" ? "is-active" : ""} aria-pressed={view === "classic"} onClick={() => selectView("classic")}>Classic</button><button className={view === "stylish" ? "is-active" : ""} aria-pressed={view === "stylish"} onClick={() => selectView("stylish")}>Stylish</button></div><div className="bo-user-menu__label">Тема</div><div className="bo-view-switch" aria-label="Тема Backoffice"><button className={theme === "light" ? "is-active" : ""} aria-pressed={theme === "light"} onClick={() => { if (theme !== "light") toggleTheme(); }}>Светлая</button><button className={theme === "dark" ? "is-active" : ""} aria-pressed={theme === "dark"} onClick={() => { if (theme !== "dark") toggleTheme(); }}>Тёмная</button></div></div></details>
      </div></header>
      <div className="bo-tabs">{tabs.map((tab) => <button key={tab.id} className={`bo-tab ${activeTab === tab.id ? "bo-tab--active" : ""}`} onClick={() => { setActiveTab(tab.id); setParams({ domain: tab.domain, ...(tab.entityId ? { id: tab.entityId } : {}) }); }}>{tab.title}{tab.dirty ? " *" : ""}{tab.id !== "overview" && <span onClick={(event) => { event.stopPropagation(); closeTab(tab.id); }}> ×</span>}</button>)}</div>
      <main className="bo-workspace"><Workspace domain={active.domain} entityId={active.entityId} query={globalQuery} warehouseId={warehouseId} data={data} commands={commands} can={can} openDomain={openDomain} /></main>
    </section>
  </div>;
}

type Data = ReturnType<typeof useBackofficeData>;
type Commands = ReturnType<typeof useBackofficeCommands>;

function Workspace({ domain, entityId, query, warehouseId, data, commands, can, openDomain }: { domain: DomainId; entityId?: string; query: string; warehouseId: string; data: Data; commands: Commands; can: (...permissions: Permission[]) => boolean; openDomain: (domain: DomainId, entityId?: string, title?: string) => void }) {
  if (domain === "overview") return <Overview data={data} openDomain={openDomain} />;
  if (domain === "equipment") return <EquipmentWorkspace data={data} commands={commands} warehouseId={warehouseId} entityId={entityId} query={query} can={can} openDomain={openDomain} />;
  if (domain === "models") return <ModelsWorkspace data={data} query={query} can={can}/>;
  if (domain === "cables") return <CableWorkspace data={data} warehouseId={warehouseId} query={query} can={can} />;
  if (domain === "catalog") return <CatalogWorkspace data={data} commands={commands} can={can} query={query} entityId={entityId} openDomain={openDomain} />;
  if (domain === "projects") return <ProjectsWorkspace data={data} entityId={entityId} commands={commands} query={query} can={can} openDomain={openDomain} />;
  if (domain === "documents") return <OperationDocument data={data} commands={commands} can={can} />;
  if (domain === "inventory") return <InventoryWorkspace data={data} commands={commands} can={can} />;
  if (domain === "movement") return <MovementWorkspace data={data} query={query} />;
  if (domain === "people") return <PeopleWorkspace data={data} commands={commands} can={can} query={query} />;
  if (domain === "contractors") return <ContractorsWorkspace data={data} commands={commands} can={can} query={query} />;
  if (domain === "finance") return <FinanceWorkspace data={data} commands={commands} can={can} />;
  if (domain === "problems") return <ProblemsWorkspace data={data} commands={commands} can={can} />;
  if (domain === "reports") return <ReportBuilder data={data} />;
  if (domain === "audit") return <AuditWorkspace data={data} query={query} />;
  return <PermissionsWorkspace data={data} commands={commands} can={can} />;
}

function Overview({ data, openDomain }: { data: Data; openDomain: (domain: DomainId) => void }) {
  const apex = data.apex.data;
  const overdue=(data.units.data??[]).filter(u=>u.status==="on_project"&&(data.projects.data??[]).find(p=>p.id===u.currentProjectId&&new Date(p.endsAt)<new Date())).length;
  const controls=[{label:"Просроченные возвраты",value:overdue,tone:"danger"},{label:"Открытые ремонты",value:data.openRepairs.data?.length??0,tone:"warn"},{label:"У подрядчиков",value:data.openHandovers.data?.length??0,tone:"warn"},{label:"Непрочитанные уведомления",value:(data.notifications.data??[]).filter(n=>!n.read).length,tone:"info"}];
  const apexLoading=data.apex.isLoading||!apex;
  return <div className="stack"><div className="bo-grid bo-grid--overview"><Metric label="Активные проекты" value={apexLoading?"…":String(apex.current.length+apex.upcoming.length)} onClick={() => openDomain("projects")} /><Metric label="Открытые проблемы" value={apexLoading?"…":String(apex.problems.length)} onClick={() => openDomain("problems")} /><Metric label="Долг клиентов" value={apexLoading?"…":money(apex.financeSummary.clientDebtEUR)} onClick={() => openDomain("finance")} /><Metric label="Единицы оборудования" value={data.units.isLoading?"…":String(data.units.data?.length??0)} onClick={() => openDomain("equipment")} /></div><section className="bo-panel"><div className="bo-panel__head"><span>Операционный контроль</span><small>Обновляется из общей базы</small></div><div className="bo-control-list">{controls.map(x=><button key={x.label} className={`is-${x.tone}`} onClick={()=>openDomain(x.label.includes("ремонт")||x.label.includes("подряд")?"equipment":x.label.includes("уведом")?"problems":"projects")}><span>{x.label}</span><strong>{x.value}</strong></button>)}</div></section><section className="bo-panel"><div className="bo-panel__head"><span>Последние уведомления</span></div>{data.notifications.isLoading?<p className="bo-note">Загрузка уведомлений…</p>:(data.notifications.data??[]).length===0?<p className="bo-note">Новых уведомлений нет</p>:(data.notifications.data??[]).slice(0,6).map(n=><article className="bo-notification" key={n.id}><Chip label={n.kind} tone={n.read?"neutral":"info"}/><div><strong>{n.title}</strong><p>{n.body}</p></div><time>{dt(n.createdAt)}</time></article>)}</section></div>;
}
function Metric({ label, value, onClick }: { label: string; value: string; onClick: () => void }) { return <button className="bo-panel bo-metric" onClick={onClick}><span>{label}</span><strong>{value}</strong></button>; }

function EquipmentWorkspace({ data, commands, warehouseId, entityId, query, can, openDomain }: { data: Data; commands:Commands; warehouseId: string; entityId?: string; query: string; can: (...permissions: Permission[]) => boolean; openDomain: (domain: DomainId, id?: string, title?: string) => void }) {
  const [importOpen,setImportOpen]=useState(false),[zonesOpen,setZonesOpen]=useState(false),[csv,setCsv]=useState("");
  const [zoneWarehouse,setZoneWarehouse]=useState(""),[zoneParent,setZoneParent]=useState(""),[zoneName,setZoneName]=useState(""),[zoneCode,setZoneCode]=useState(""),[zoneKind,setZoneKind]=useState<Equipment.StorageZoneKind>("rack");
  const createZone=useCreateStorageZone(),updateZone=useUpdateStorageZone();
  const models = data.models.data ?? [], units = (data.units.data ?? []).filter((unit) => warehouseId === "all" || unit.warehouseId === warehouseId);
  const warehouses = new Map((data.warehouses.data ?? []).map((row) => [row.id, row.name]));
  const effectiveZoneWarehouse=zoneWarehouse||(data.warehouses.data?.[0]?.id??""), zoneRows=(data.storageZones.data??[]).filter(z=>z.warehouseId===effectiveZoneWarehouse);
  const zones = new Map((data.storageZones.data??[]).map(z=>[z.id,`${z.code} · ${z.name}`]));
  const modelMap = new Map(models.map((row) => [row.id, row]));
  const columns: RegisterColumn<Equipment.EquipmentUnitDTO>[] = [
    { id: "tag", label: "Маркировка", value: (row) => row.assetTag }, { id: "model", label: "Модель", value: (row) => modelMap.get(row.modelId)?.name ?? row.modelId }, { id: "serial", label: "Серийный №", value: (row) => row.serial ?? "—" }, { id: "status", label: "Статус", value: (row) => statusLabel[row.status] ?? row.status }, { id: "warehouse", label: "Склад", value: (row) => warehouses.get(row.warehouseId ?? "") ?? "—" }, {id:"zone",label:"Зона",value:(row)=>zones.get(row.zoneId??"")??"Без зоны"}, { id: "cost", label: "Стоимость", value: (row) => modelMap.get(row.modelId)?.unitCostEUR ?? 0, render: (row) => money(modelMap.get(row.modelId)?.unitCostEUR ?? 0), align: "right" },
  ];
  return <>{importOpen&&<section className="bo-panel bo-import"><div><h2>Импорт оборудования</h2><p>Используется общая схема mobile/desktop. Перед большим импортом сделайте резервную копию.</p></div><textarea aria-label="CSV оборудования" value={csv} onChange={e=>setCsv(e.target.value)} placeholder="type,model,manufacturer,unitCostEUR,dailyPriceEUR,assetTag,serial,warehouse"/><div className="bo-form-actions"><button onClick={()=>setImportOpen(false)}>Отмена</button><button className="bo-primary" disabled={!csv.trim()||commands.importEquipmentCsv.isPending} onClick={()=>commands.importEquipmentCsv.mutate(csv,{onSuccess:r=>{setCsv("");setImportOpen(false);alert(`Импортировано моделей: ${r.modelsCreated}, единиц: ${r.unitsCreated}`);}})}>Проверить и импортировать</button></div></section>}{zonesOpen&&<section className="bo-panel bo-zone-manager"><div className="bo-panel__head"><span>Зоны хранения</span><small>Необязательно: помещение → стеллаж → полка</small></div><div className="bo-form-grid"><label>Склад<select value={effectiveZoneWarehouse} onChange={e=>{setZoneWarehouse(e.target.value);setZoneParent("");}}>{(data.warehouses.data??[]).map(w=><option key={w.id} value={w.id}>{w.name}</option>)}</select></label><label>Родитель<select value={zoneParent} onChange={e=>setZoneParent(e.target.value)}><option value="">Корневая зона</option>{zoneRows.filter(z=>z.active).map(z=><option key={z.id} value={z.id}>{z.code} · {z.name}</option>)}</select></label><label>Код<input aria-label="Код зоны" value={zoneCode} onChange={e=>setZoneCode(e.target.value)} placeholder="A-03-02"/></label><label>Название<input aria-label="Название зоны" value={zoneName} onChange={e=>setZoneName(e.target.value)} placeholder="Полка 2"/></label><label>Вид<select value={zoneKind} onChange={e=>setZoneKind(e.target.value as Equipment.StorageZoneKind)}><option value="room">Помещение</option><option value="floor">Напольная зона</option><option value="rack">Стеллаж</option><option value="shelf">Полка</option><option value="bin">Ячейка</option><option value="other">Другое</option></select></label></div><div className="bo-form-actions"><button onClick={()=>setZonesOpen(false)}>Закрыть</button><button className="bo-primary" disabled={!effectiveZoneWarehouse||!zoneCode.trim()||!zoneName.trim()||createZone.isPending} onClick={()=>createZone.mutate({warehouseId:effectiveZoneWarehouse,parentId:zoneParent||null,name:zoneName.trim(),code:zoneCode.trim(),kind:zoneKind},{onSuccess:()=>{setZoneCode("");setZoneName("");}})}>Добавить зону</button></div><table className="bo-table"><thead><tr><th>Код</th><th>Название</th><th>Вид</th><th>Состояние</th></tr></thead><tbody>{zoneRows.map(z=><tr key={z.id}><td>{z.code}</td><td>{z.name}</td><td>{storageZoneKindLabel[z.kind]}</td><td><button onClick={()=>updateZone.mutate({id:z.id,input:{active:!z.active}})}>{z.active?"Активна":"Архив"}</button></td></tr>)}</tbody></table></section>}<div className="bo-split"><Register id="equipment" rows={units} columns={columns} rowKey={(row) => row.id} externalQuery={query} onOpen={(row) => openDomain("equipment", row.id, row.assetTag)} toolbar={can("warehouse.catalog.manage")?<><button onClick={()=>setZonesOpen(v=>!v)}>Зоны хранения</button><button className="bo-primary" onClick={()=>setImportOpen(true)}>Импорт CSV</button></>:null} />{entityId && <EquipmentDetail id={entityId} data={data} can={can} openDomain={openDomain} />}</div></>;
}

function ModelsWorkspace({data,query,can}:{data:Data;query:string;can:(...permissions:Permission[])=>boolean}){
  const [selected,setSelected]=useState<Equipment.EquipmentModelDTO|null>(null),[color,setColor]=useState("all"), types=new Map((data.types.data??[]).map(t=>[t.id,t.name])), units=data.units.data??[];
  const feature=(m:Equipment.EquipmentModelDTO)=>{const a=m.attrs as Record<string,unknown>|null;if(!a)return "—";return [a.colorSystem,a.fixtureClass,Array.isArray(a.protocols)?a.protocols.join("/"):null,a.interface].filter(Boolean).join(" · ")||"—";};
  const colorSystems=[...new Set((data.models.data??[]).map(m=>(m.attrs as Record<string,unknown>|null)?.colorSystem).filter((v):v is string=>typeof v==="string"))].sort(), rows=(data.models.data??[]).filter(m=>color==="all"||(m.attrs as Record<string,unknown>|null)?.colorSystem===color);
  const columns:RegisterColumn<Equipment.EquipmentModelDTO>[]=[{id:"name",label:"Модель",value:m=>m.name},{id:"manufacturer",label:"Производитель",value:m=>m.manufacturer??"—"},{id:"type",label:"Тип",value:m=>types.get(m.typeId)??"—"},{id:"features",label:"Ключевые отличия",value:feature},{id:"tracking",label:"Учёт",value:m=>m.trackingMode==="serial"?"Серийный":m.trackingMode==="cable"?"Кабель":"Количество"},{id:"units",label:"Единиц",value:m=>m.trackingMode==="serial"?units.filter(u=>u.modelId===m.id).length:"остаток"},{id:"kit",label:"Комплектность",value:m=>m.requiredComponentModelIds.length?`${m.requiredComponentModelIds.length} обязательных поз.`:"—"}];
  return <><Register id="models" rows={rows} columns={columns} rowKey={m=>m.id} externalQuery={query} onOpen={m=>setSelected(m)} toolbar={<><span className="bo-note">RGB / RGBW / RGBWAUV, протоколы и комплектность видны без открытия карточки</span><select aria-label="Цветовая система" value={color} onChange={e=>setColor(e.target.value)}><option value="all">Все цветовые системы</option>{colorSystems.map(x=><option key={x} value={x}>{x}</option>)}</select></>}/><EditModelSheet model={can("warehouse.catalog.manage")?selected:null} onClose={()=>setSelected(null)}/>{selected&&!can("warehouse.catalog.manage")&&<section className="bo-panel"><h2>{selected.name}</h2><p>{feature(selected)}</p><button onClick={()=>setSelected(null)}>Закрыть</button></section>}</>;
}

function CableWorkspace({data,warehouseId,query,can}:{data:Data;warehouseId:string;query:string;can:(...permissions:Permission[])=>boolean}){
  const [selected,setSelected]=useState<Equipment.EquipmentModelDTO|null>(null),[kind,setKind]=useState("all");
  const models=(data.models.data??[]).filter(m=>m.trackingMode==="cable"||m.trackingMode==="quantity"), kinds=[...new Set(models.map(m=>m.trackingMode==="cable"?(cableAttrs(m)?.cableType||"Другое"):"Комплектующие"))].sort();
  const q=query.trim().toLowerCase();
  const shown=models.filter(m=>{const a=cableAttrs(m),group=m.trackingMode==="cable"?(a?.cableType||"Другое"):"Комплектующие";return (kind==="all"||group===kind)&&(!q||[m.name,group,a?.sideAConnector,a?.sideBConnector,a?.lengthM].some(v=>String(v??"").toLowerCase().includes(q)));});
  return <><section className="bo-panel bo-cable-summary"><div><div className="bo-eyebrow">Кабели и мелкие комплектующие</div><h2>{shown.length} моделей</h2><p>Фильтруйте по назначению, длине, разъёму или питанию. Остатки показаны для выбранного склада.</p></div><label>Назначение<select value={kind} onChange={e=>setKind(e.target.value)}><option value="all">Все кабели</option>{kinds.map(x=><option key={x} value={x}>{x}</option>)}</select></label></section><section className="bo-panel bo-cable-list"><div className="bo-cable-head"><span>Кабель</span><span>Разъёмы</span><span>Место</span><span>Остаток</span><span></span></div>{shown.map(m=><CableStockRow key={m.id} model={m} warehouseId={warehouseId} zones={data.storageZones.data??[]} canMove={can("warehouse.issue","warehouse.catalog.manage")} canEdit={can("warehouse.catalog.manage")} onMove={()=>setSelected(m)}/>)}</section><CableMoveSheet model={selected} projects={data.projects.data??[]} warehouses={data.warehouses.data??[]} selectedWarehouseId={warehouseId==="all"?null:warehouseId} onClose={()=>setSelected(null)}/></>;
}

function CableStockRow({model,warehouseId,zones,canMove,canEdit,onMove}:{model:Equipment.EquipmentModelDTO;warehouseId:string;zones:Equipment.StorageZoneDTO[];canMove:boolean;canEdit:boolean;onMove:()=>void}){
  const aggregate=useModelStock(model.id,warehouseId==="all"), scoped=useModelStockAtWarehouse(model.id,warehouseId==="all"?"":warehouseId,warehouseId!=="all"), stock=warehouseId==="all"?aggregate.data:scoped.data, attrs=cableAttrs(model), setStock=useSetModelStock();
  const zoneOptions=zones.filter(z=>z.active&&(warehouseId==="all"||z.warehouseId===warehouseId));
  return <article className="bo-cable-row"><div><strong>{model.trackingMode==="cable"?formatCableModel(model):model.name}</strong><small>{model.trackingMode==="cable"?`${attrs?.cableType||"Кабель"} · ${attrs?.lengthM??"—"} м`:"Комплектующая · количественный учёт"}</small></div><div>{model.trackingMode==="cable"?<><span>{attrs?.sideAQty}× {attrs?.sideAConnector}</span><span>{attrs?.sideBQty}× {attrs?.sideBConnector}</span></>:<span>—</span>}</div><div>{warehouseId==="all"?<span className="bo-note">Выберите склад</span>:<select aria-label={`Зона ${model.name}`} value={stock?.zoneId??""} disabled={!canEdit||!stock} onChange={e=>stock&&setStock.mutate({modelId:model.id,warehouseId,total:stock.total,zoneId:e.target.value||null})}><option value="">Без зоны</option>{zoneOptions.map(z=><option key={z.id} value={z.id}>{z.code} · {z.name}</option>)}</select>}</div><div><strong>{stock?.inStock??"…"}</strong><small>из {stock?.total??"…"} · на проектах {stock?.onProjects??"…"}</small></div><button disabled={!canMove} onClick={onMove}>Выдать / принять</button></article>;
}

const journalLabel: Record<Equipment.JournalAction, string> = { created: "Создано", reserved: "Зарезервировано", issued: "Выдано на проект", returned: "Возвращено", return_incomplete: "Некомплект", sent_to_repair: "В ремонт", back_from_repair: "Из ремонта", sent_to_contractor: "Подрядчику", back_from_contractor: "От подрядчика", marked_lost: "Утеряно", transferred: "Перемещено", status_changed: "Смена статуса" };
function EquipmentDetail({ id, data, can, openDomain }: { id: string; data: Data; can: (...permissions: Permission[]) => boolean; openDomain: (domain: DomainId, id?: string, title?: string) => void }) {
  const unit = useUnit(id), journal = useUnitJournal(id), repairs = useUnitRepairs(id), handovers = useUnitHandovers(id);
  const update = useUpdateUnit(), updateModel = useUpdateModel(), transfer = useTransferUnit(), changeStatus = useChangeStatus();
  const [assetTag, setAssetTag] = useState(""), [serial, setSerial] = useState(""), [notes, setNotes] = useState("");
  const [modelId, setModelId] = useState(""), [warehouseId, setWarehouseId] = useState(""), [zoneId,setZoneId]=useState("");
  const [typeId, setTypeId] = useState(""), [modelName, setModelName] = useState(""), [manufacturer, setManufacturer] = useState("");
  const [unitCost, setUnitCost] = useState("0"), [dailyPrice, setDailyPrice] = useState("0");
  const [requiredIds,setRequiredIds]=useState<string[]>([]);
  const u = unit.data;
  const models = data.models.data ?? [], selectedModel = models.find((m) => m.id === modelId);
  useEffect(() => { if (u) { setAssetTag(u.assetTag); setSerial(u.serial ?? ""); setNotes(u.notes ?? ""); setModelId(u.modelId); setWarehouseId(u.warehouseId ?? ""); setZoneId(u.zoneId??""); } }, [u?.id, u?.assetTag, u?.serial, u?.notes, u?.modelId, u?.warehouseId, u?.zoneId]);
  useEffect(() => { if (selectedModel) { setTypeId(selectedModel.typeId); setModelName(selectedModel.name); setManufacturer(selectedModel.manufacturer ?? ""); setUnitCost(String(selectedModel.unitCostEUR)); setDailyPrice(String(selectedModel.dailyPriceEUR)); setRequiredIds(selectedModel.requiredComponentModelIds); } }, [selectedModel?.id, selectedModel?.typeId, selectedModel?.name, selectedModel?.manufacturer, selectedModel?.unitCostEUR, selectedModel?.dailyPriceEUR, selectedModel?.requiredComponentModelIds]);
  if (unit.isLoading) return <aside className="bo-panel bo-peek"><p>Загрузка карточки…</p></aside>;
  if (!u) return <aside className="bo-panel bo-peek"><h2>Карточка не найдена</h2><button onClick={() => unit.refetch()}>Повторить</button></aside>;
  const model = models.find((m) => m.id === u.modelId), type = data.types.data?.find((t) => t.id === model?.typeId);
  const warehouseName = (wid: string | null) => data.warehouses.data?.find((w) => w.id === wid)?.name ?? "—", zoneName=(zid:string|null)=>data.storageZones.data?.find(z=>z.id===zid)?.name??"Без зоны";
  const project = data.projects.data?.find((p) => p.id === u.currentProjectId), cable = model ? cableAttrs(model) : null;
  const technicalAttrs=model?.attrs&&!cable?Object.entries(model.attrs):[], requiredModels=(model?.requiredComponentModelIds??[]).map(mid=>models.find(m=>m.id===mid)).filter(Boolean) as Equipment.EquipmentModelDTO[];
  const repairTotal = (repairs.data ?? []).filter((r) => r.status === "closed").reduce((sum, r) => sum + (r.costEUR ?? 0), 0);
  return <aside className="bo-panel bo-peek bo-unit-card">
    <div className="bo-panel__head"><span>Карточка оборудования</span><Chip label={statusLabel[u.status] ?? u.status} tone={u.status === "lost" ? "danger" : "info"} /></div>
    <h2>{u.assetTag}</h2><p className="bo-note">{model?.name ?? "Неизвестная модель"}{model?.manufacturer ? ` · ${model.manufacturer}` : ""}</p>
    <section className="bo-card-section"><h3>Основное</h3><dl className="bo-details"><dt>Тип</dt><dd>{type?.name ?? "—"}</dd><dt>Склад</dt><dd>{warehouseName(u.warehouseId)}</dd><dt>Зона хранения</dt><dd>{zoneName(u.zoneId)}</dd><dt>Проект</dt><dd>{project ? <button className="bo-link" onClick={() => openDomain("projects", project.id, project.name)}>{project.name}</button> : "—"}</dd><dt>В системе с</dt><dd>{dt(u.createdAt)}</dd>{can("warehouse.costs.view") && <><dt>Стоимость замены</dt><dd>{model ? money(model.unitCostEUR) : "—"}</dd><dt>Аренда / сутки</dt><dd>{model ? money(model.dailyPriceEUR) : "—"}</dd><dt>Ремонты</dt><dd>{repairTotal ? money(repairTotal) : "—"}</dd></>}</dl>{cable && <dl className="bo-details"><dt>Кабель</dt><dd>{cable.cableType}, {cable.lengthM} м</dd><dt>Сторона A</dt><dd>{cable.sideAQty}× {cable.sideAConnector}</dd><dt>Сторона B</dt><dd>{cable.sideBQty}× {cable.sideBConnector}</dd></dl>}</section>
    {(technicalAttrs.length>0||requiredModels.length>0)&&<section className="bo-card-section"><h3>Технические данные и комплектность</h3>{technicalAttrs.length>0&&<dl className="bo-details">{technicalAttrs.map(([key,value])=><Fragment key={key}><dt>{key}</dt><dd>{Array.isArray(value)?value.join(", "):String(value)}</dd></Fragment>)}</dl>}{requiredModels.length>0&&<div className="bo-required"><strong>Обязательно выдавать вместе</strong>{requiredModels.map(m=><span key={m.id}>{m.name}</span>)}</div>}</section>}
    <section className="bo-card-section"><h3>Учётные данные единицы</h3><label>Инвентарный номер<input value={assetTag} disabled={!can("warehouse.catalog.manage")} onChange={(e) => setAssetTag(e.target.value)} /></label><label>Серийный номер<input value={serial} disabled={!can("warehouse.unit.status")} onChange={(e) => setSerial(e.target.value)} /></label><label>Модель<select aria-label="Модель оборудования" value={modelId} disabled={!can("warehouse.catalog.manage")} onChange={(e) => setModelId(e.target.value)}>{models.map(m=><option key={m.id} value={m.id}>{m.name}{m.manufacturer?` · ${m.manufacturer}`:""}</option>)}</select></label><label>Склад<select aria-label="Склад оборудования" value={warehouseId} disabled={!can("warehouse.catalog.manage")||u.status!=="in_stock"} onChange={(e)=>{setWarehouseId(e.target.value);setZoneId("");}}>{(data.warehouses.data??[]).map(w=><option key={w.id} value={w.id}>{w.name}</option>)}</select></label><label>Зона хранения (необязательно)<select aria-label="Зона хранения" value={zoneId} disabled={!can("warehouse.catalog.manage")||u.status!=="in_stock"} onChange={e=>setZoneId(e.target.value)}><option value="">Без зоны</option>{(data.storageZones.data??[]).filter(z=>z.warehouseId===warehouseId&&z.active).map(z=><option key={z.id} value={z.id}>{z.code} · {z.name}</option>)}</select></label>{u.status!=="in_stock"&&<p className="bo-note">Склад и зону можно изменить после возврата единицы на склад.</p>}<label>Особенности и дефекты<textarea value={notes} disabled={!can("warehouse.unit.status")} onChange={(e) => setNotes(e.target.value)} /></label>{can("warehouse.unit.status", "warehouse.catalog.manage") && <button className="bo-primary" disabled={!assetTag.trim()||!modelId||update.isPending||transfer.isPending} onClick={async()=>{await update.mutateAsync({id,input:{modelId,assetTag:assetTag.trim(),serial:serial.trim()||null,notes:notes.trim()||null}});if(warehouseId&&(warehouseId!==u.warehouseId||(zoneId||null)!==u.zoneId))await transfer.mutateAsync({id,warehouseId,zoneId:zoneId||null,note:"Изменено из карточки оборудования"});}}>Сохранить единицу</button>}</section>
    {can("warehouse.catalog.manage")&&selectedModel&&<section className="bo-card-section"><h3>Модель и тип</h3><p className="bo-note">Изменения этого блока применятся ко всем единицам модели «{selectedModel.name}».</p><label>Тип<select aria-label="Тип оборудования" value={typeId} onChange={e=>setTypeId(e.target.value)}>{(data.types.data??[]).map(t=><option key={t.id} value={t.id}>{t.name} · {t.trackingMode}</option>)}</select></label><label>Название модели<input value={modelName} onChange={e=>setModelName(e.target.value)}/></label><label>Производитель<input value={manufacturer} onChange={e=>setManufacturer(e.target.value)}/></label><div className="bo-form-grid"><label>Стоимость замены, EUR<input type="number" min="0" step="0.01" value={unitCost} onChange={e=>setUnitCost(e.target.value)}/></label><label>Аренда / сутки, EUR<input type="number" min="0" step="0.01" value={dailyPrice} onChange={e=>setDailyPrice(e.target.value)}/></label></div><label>Обязательная комплектность<select multiple size={6} aria-label="Обязательные комплектующие" value={requiredIds} onChange={e=>setRequiredIds(Array.from(e.currentTarget.selectedOptions,o=>o.value))}>{models.filter(m=>m.id!==selectedModel.id).map(m=><option key={m.id} value={m.id}>{m.name}</option>)}</select></label><p className="bo-note">Выберите питание, сеть, адаптеры и другие позиции, которые должны выдаваться вместе.</p><button className="bo-primary" disabled={!typeId||!modelName.trim()||Number(unitCost)<0||Number(dailyPrice)<0||updateModel.isPending} onClick={()=>updateModel.mutate({id:selectedModel.id,input:{typeId,name:modelName.trim(),manufacturer:manufacturer.trim()||null,unitCostEUR:Number(unitCost),dailyPriceEUR:Number(dailyPrice),requiredComponentModelIds:requiredIds}})}>Сохранить модель и тип</button></section>}
    {can("warehouse.unit.status") && <><section className="bo-card-section"><h3>Статус</h3><select aria-label="Статус оборудования" value={u.status} disabled={changeStatus.isPending} onChange={(e) => changeStatus.mutate({ id, status: e.target.value as Equipment.UnitStatus })}>{(["in_stock","reserved","in_repair","at_contractor","lost"] as Equipment.UnitStatus[]).map((s) => <option key={s} value={s}>{statusLabel[s]}</option>)}</select></section><RepairContractorPanel unit={u} /></>}
    <section className="bo-card-section"><h3>История</h3>{journal.isLoading ? <p>Загрузка…</p> : !(journal.data?.length) ? <p className="bo-note">Событий пока нет</p> : <div className="bo-timeline">{journal.data.slice().reverse().map((e) => { const p = data.projects.data?.find((x) => x.id === e.projectId), actor = data.people.data?.find((x) => x.id === e.actorId); return <article key={e.id}><strong>{journalLabel[e.action] ?? e.action}</strong><time>{dt(e.at)}</time><p>{[p?.name, e.toWarehouseId ? warehouseName(e.toWarehouseId) : null, actor?.displayName, e.note].filter(Boolean).join(" · ")}</p></article>; })}</div>}</section>
    {(repairs.data?.length || handovers.data?.length) ? <p className="bo-note">Сервис: {repairs.data?.length ?? 0} ремонтов · {handovers.data?.length ?? 0} передач подрядчикам</p> : null}
  </aside>;
}

function CatalogWorkspace({ data, commands, can, query, entityId, openDomain }: { data: Data; commands: Commands; can: (...permissions: Permission[]) => boolean; query: string; entityId?:string; openDomain:(domain:DomainId,id?:string,title?:string)=>void }) {
  const [creating,setCreating]=useState(false), [sku,setSku]=useState(""), [name,setName]=useState(""), [kind,setKind]=useState<Catalog.CatalogItemKind>("product"), [group,setGroup]=useState(""), [unit,setUnit]=useState("pcs");
  const detail=useCatalogItemDetail(entityId), selected=(data.catalog.data??[]).find(x=>x.id===entityId);
  const columns: RegisterColumn<Catalog.CatalogItemDTO>[] = [{ id: "sku", label: "SKU", value: (r) => r.sku }, { id: "name", label: "Название", value: (r) => r.name }, { id: "kind", label: "Тип", value: (r) => catalogKindLabel[r.kind] }, { id: "group", label: "Группа", value: (r) => r.groupName ?? "—" }, { id: "unit", label: "Базовая ед.", value: (r) => catalogUnitLabel[r.baseUnit] ?? r.baseUnit }, { id: "state", label: "Состояние", value: (r) => r.active ? "Активна" : "Архив" }];
  return <>{creating&&<section className="bo-panel bo-inline-form"><label>SKU<input value={sku} onChange={e=>setSku(e.target.value)} /></label><label>Название<input value={name} onChange={e=>setName(e.target.value)} /></label><label>Тип<select value={kind} onChange={e=>setKind(e.target.value as Catalog.CatalogItemKind)}><option value="product">Расходный материал</option><option value="item">Складская позиция</option><option value="semi_finished">Сборочная заготовка</option><option value="modifier">Дополнение</option><option value="equipment_kit">Комплект</option></select></label><label>Группа<input value={group} onChange={e=>setGroup(e.target.value)} /></label><label>Базовая единица<input value={unit} onChange={e=>setUnit(e.target.value)} /></label><button className="bo-primary" disabled={!sku.trim()||!name.trim()||!unit.trim()||commands.createCatalogItem.isPending} onClick={()=>commands.createCatalogItem.mutate({sku:sku.trim(),name:name.trim(),kind,groupName:group.trim()||null,baseUnit:unit.trim()},{onSuccess:()=>{setCreating(false);setSku("");setName("");setGroup("");}})}>Создать позицию</button><button onClick={()=>setCreating(false)}>Отмена</button></section>}<div className="bo-split"><Register id="catalog" rows={data.catalog.data ?? []} columns={columns} rowKey={(row) => row.id} externalQuery={query} onOpen={row=>openDomain("catalog",row.id,row.name)} toolbar={can("warehouse.catalog.manage")?<button className="bo-primary" onClick={()=>setCreating(true)}>Новая позиция</button>:null} />{selected&&<CatalogDetail item={selected} all={data.catalog.data??[]} detail={detail} commands={commands} can={can} />}</div></>;
}

function CatalogDetail({item,all,detail,commands,can}:{item:Catalog.CatalogItemDTO;all:Catalog.CatalogItemDTO[];detail:ReturnType<typeof useCatalogItemDetail>;commands:Commands;can:(...permissions:Permission[])=>boolean}) { const [packageOpen,setPackageOpen]=useState(false),[recipeOpen,setRecipeOpen]=useState(false),[packName,setPackName]=useState(""),[coefficient,setCoefficient]=useState("1"),[barcode,setBarcode]=useState(""),[ingredient,setIngredient]=useState(""),[gross,setGross]=useState("1"),[technology,setTechnology]=useState(""); const recipes=detail.recipes.data??[], packaging=detail.packaging.data??[]; return <aside className="bo-panel bo-peek bo-unit-card"><div className="bo-panel__head"><span>Карточка расходника или комплекта</span><Chip label={item.active?"Активна":"Архив"} tone={item.active?"ok":"neutral"}/></div><h2>{item.name}</h2><dl className="bo-details"><dt>SKU</dt><dd>{item.sku}</dd><dt>Тип</dt><dd>{catalogKindLabel[item.kind]}</dd><dt>Группа</dt><dd>{item.groupName??"—"}</dd><dt>Базовая единица</dt><dd>{catalogUnitLabel[item.baseUnit] ?? item.baseUnit}</dd></dl><section className="bo-card-section"><div className="bo-section-title"><h3>Упаковки</h3>{can("warehouse.catalog.manage")&&<button onClick={()=>setPackageOpen(v=>!v)}>+ Добавить</button>}</div>{packageOpen&&<div className="bo-mini-form"><input aria-label="Название упаковки" placeholder="Коробка" value={packName} onChange={e=>setPackName(e.target.value)}/><input aria-label="Коэффициент" type="number" min="0.001" step="0.001" value={coefficient} onChange={e=>setCoefficient(e.target.value)}/><input aria-label="Штрихкод" placeholder="Штрихкод" value={barcode} onChange={e=>setBarcode(e.target.value)}/><button className="bo-primary" disabled={!packName.trim()||Number(coefficient)<=0} onClick={()=>commands.addPackaging.mutate({itemId:item.id,input:{name:packName.trim(),coefficient:Number(coefficient),barcode:barcode.trim()||null,supplierCode:null,active:true}},{onSuccess:()=>{setPackageOpen(false);setPackName("");setBarcode("");}})}>Сохранить</button></div>}{!packaging.length?<p className="bo-note">Упаковок пока нет</p>:<table className="bo-table"><tbody>{packaging.map(p=><tr key={p.id}><td>{p.name}</td><td>{p.coefficient} {catalogUnitLabel[item.baseUnit] ?? item.baseUnit}</td><td>{p.barcode??"—"}</td></tr>)}</tbody></table>}</section><section className="bo-card-section"><div className="bo-section-title"><h3>Состав комплекта</h3>{can("warehouse.catalog.manage")&&<button onClick={()=>setRecipeOpen(v=>!v)}>+ Версия</button>}</div>{recipeOpen&&<div className="bo-mini-form"><select aria-label="Компонент комплекта" value={ingredient} onChange={e=>setIngredient(e.target.value)}><option value="">Выберите компонент</option>{all.filter(x=>x.id!==item.id).map(x=><option key={x.id} value={x.id}>{x.name}</option>)}</select><input aria-label="Количество компонента" type="number" min="0" step="0.001" value={gross} onChange={e=>setGross(e.target.value)}/><textarea aria-label="Инструкция по комплектации" placeholder="Инструкция по комплектации" value={technology} onChange={e=>setTechnology(e.target.value)}/><button className="bo-primary" disabled={!ingredient||Number(gross)<=0} onClick={()=>commands.createRecipe.mutate({itemId:item.id,input:{version:(recipes[0]?.version??0)+1,validFrom:new Date().toISOString(),validTo:null,outputQty:1,outputUnit:item.baseUnit,technology:technology.trim()||null,lines:[{ingredientItemId:ingredient,unit:all.find(x=>x.id===ingredient)?.baseUnit??"pcs",grossQty:Number(gross),netQty:Number(gross),baseQty:Number(gross)}]}},{onSuccess:()=>{setRecipeOpen(false);setIngredient("");setTechnology("");}})}>Создать версию</button></div>}{!recipes.length?<p className="bo-note">Состав пока не задан</p>:recipes.map(r=><article className="bo-recipe" key={r.id}><strong>Версия {r.version}</strong><span>Выход: {r.outputQty} {catalogUnitLabel[r.outputUnit] ?? r.outputUnit}</span><p>{r.technology??"Без инструкции по комплектации"}</p>{r.lines.map(line=><small key={line.id}>{all.find(x=>x.id===line.ingredientItemId)?.name??line.ingredientItemId}: {line.netQty} {catalogUnitLabel[line.unit] ?? line.unit}</small>)}</article>)}</section></aside>; }

function ProjectsWorkspace({ data, entityId, commands, query, can, openDomain }: { data: Data; entityId?: string; commands: Commands; query: string; can:(...permissions:Permission[])=>boolean; openDomain: (domain: DomainId, id?: string, title?: string) => void }) {
  const [creating,setCreating]=useState(false);
  const projects = data.projects.data ?? [], clients = new Map((data.clients.data ?? []).map((row) => [row.id, row.name]));
  const selected = projects.find((row) => row.id === entityId);
  const columns: RegisterColumn<Projects.ProjectDTO>[] = [{ id: "name", label: "Проект", value: (row) => row.name }, { id: "client", label: "Клиент", value: (row) => clients.get(row.clientId) ?? "—" }, { id: "starts", label: "Начало", value: (row) => dt(row.startsAt) }, { id: "ends", label: "Окончание", value: (row) => dt(row.endsAt) }, { id: "status", label: "Статус", value: (row) => statusLabel[row.status] ?? row.status }];
  if (selected && !creating) return <ProjectDetailPage projectId={selected.id} embedded />;
  return <div className="bo-split"><Register id="projects" rows={projects} columns={columns} rowKey={(row) => row.id} externalQuery={query} onOpen={(row) => openDomain("projects", row.id, row.name)} toolbar={can("projects.manage")?<button className="bo-primary" onClick={()=>setCreating(true)}>Новый проект</button>:null} />{creating&&<NewProject clients={data.clients.data??[]} pending={commands.createProject.isPending} cancel={()=>setCreating(false)} save={input=>commands.createProject.mutate(input,{onSuccess:p=>{setCreating(false);openDomain("projects",p.id,p.name);}})} />}</div>;
}
function NewProject({clients,pending,cancel,save}:{clients:Projects.ClientDTO[];pending:boolean;cancel:()=>void;save:(input:Projects.CreateProjectInput)=>void}) { const now=new Date(), later=new Date(now.getTime()+86400000); const [name,setName]=useState(""),[clientId,setClientId]=useState(clients[0]?.id??""),[startsAt,setStartsAt]=useState(now.toISOString().slice(0,16)),[endsAt,setEndsAt]=useState(later.toISOString().slice(0,16)); const valid=!!name.trim()&&!!clientId&&new Date(endsAt)>new Date(startsAt); return <aside className="bo-panel bo-peek"><div className="bo-panel__head"><span>Новый проект</span></div><label>Название<input value={name} onChange={e=>setName(e.target.value)} /></label><label>Клиент<select value={clientId} onChange={e=>setClientId(e.target.value)}>{clients.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}</select></label><label>Начало<input type="datetime-local" value={startsAt} onChange={e=>setStartsAt(e.target.value)} /></label><label>Окончание<input type="datetime-local" value={endsAt} onChange={e=>setEndsAt(e.target.value)} /></label><div className="bo-form-actions"><button onClick={cancel}>Отмена</button><button className="bo-primary" disabled={!valid||pending} onClick={()=>save({name:name.trim(),clientId,startsAt:new Date(startsAt).toISOString(),endsAt:new Date(endsAt).toISOString()})}>Создать проект</button></div></aside>; }

function OperationDocument({ data, commands, can }: { data: Data; commands: Commands; can: (...permissions: Permission[]) => boolean }) {
  const [kind, setKind] = useState<"issue" | "return" | "transfer">("issue"); const [projectId, setProjectId] = useState(""); const [warehouseId, setWarehouseId] = useState(""); const [selected, setSelected] = useState<string[]>([]); const [note,setNote]=useState(""),[scan,setScan]=useState(""),[scanMessage,setScanMessage]=useState<{tone:"ok"|"error";text:string}|null>(null); const units = data.units.data ?? [];
  const eligible = kind === "issue" ? units.filter((u) => u.status === "in_stock") : kind === "return" ? units.filter((u) => u.status === "on_project" && (!projectId || u.currentProjectId === projectId)) : units;
  const models=data.models.data??[], selectedModels=selected.map(id=>units.find(u=>u.id===id)).map(u=>models.find(m=>m.id===u?.modelId)).filter(Boolean) as Equipment.EquipmentModelDTO[], requiredIds=[...new Set(selectedModels.flatMap(m=>m.requiredComponentModelIds))], requirements=requiredIds.map(id=>models.find(m=>m.id===id)).filter(Boolean) as Equipment.EquipmentModelDTO[];
  const addSerialRequirements=()=>{const additions=requirements.filter(m=>m.trackingMode==="serial").map(m=>eligible.find(u=>u.modelId===m.id&&!selected.includes(u.id))?.id).filter((id):id is string=>!!id);setSelected(current=>[...new Set([...current,...additions])]);};
  const saveDraft = () => { const payload:Operations.OperationPayload=kind==="issue"?{kind,projectId,unitIds:selected,note:note.trim()||null}:kind==="return"?{kind,projectId,expectedUnitIds:eligible.map(u=>u.id),returnedUnitIds:selected,note:note.trim()||null}:{kind,unitId:selected[0]!,warehouseId,note:note.trim()||null}; commands.createDocument.mutate(payload,{onSuccess:()=>{setSelected([]);setNote("");}}); };
  const docs=data.documents.data??[];
  const scanUnit=()=>{const code=scan.trim().toLocaleLowerCase();const unit=eligible.find(u=>u.assetTag.toLocaleLowerCase()===code||(u.serial??"").toLocaleLowerCase()===code);if(!unit)setScanMessage({tone:"error",text:`Код «${scan.trim()}» не найден среди доступных единиц`});else if(selected.includes(unit.id))setScanMessage({tone:"error",text:`${unit.assetTag} уже добавлено`});else{setSelected(kind==="transfer"?[unit.id]:current=>[...current,unit.id]);setScanMessage({tone:"ok",text:`${unit.assetTag} добавлено`});}setScan("");};
  return <><section className="bo-panel"><div className="bo-document-head"><div><div className="bo-eyebrow">Операционный документ · новый черновик</div><h2>{kind === "issue" ? "Выдача" : kind === "return" ? "Возврат" : "Перемещение"}</h2></div><button className="bo-primary" disabled={!can("warehouse.issue") || !selected.length || (kind !== "transfer" && !projectId) || (kind==="transfer"&&!warehouseId)} onClick={saveDraft}>Сохранить черновик</button></div><div className="bo-doc-fields"><label>Тип<select value={kind} onChange={(e) => { setKind(e.target.value as typeof kind); setSelected([]); }}><option value="issue">Выдача</option><option value="return">Возврат</option><option value="transfer">Перемещение</option></select></label>{kind !== "transfer" && <label>Проект<select value={projectId} onChange={(e) => setProjectId(e.target.value)}><option value="">Выберите проект</option>{(data.projects.data ?? []).map((p) => <option key={p.id} value={p.id}>{p.name}</option>)}</select></label>}{kind === "transfer" && <label>Склад назначения<select value={warehouseId} onChange={(e) => setWarehouseId(e.target.value)}><option value="">Выберите склад</option>{(data.warehouses.data ?? []).map((w) => <option key={w.id} value={w.id}>{w.name}</option>)}</select></label>}<label>Комментарий<input value={note} onChange={e=>setNote(e.target.value)} placeholder="Основание или примечание" /></label></div><div className="bo-scanner"><div><strong>Сканер</strong><span>Инвентарный или серийный номер · Enter</span></div><input aria-label="Сканер оборудования" autoComplete="off" value={scan} onChange={e=>setScan(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"&&scan.trim())scanUnit();}} placeholder="Отсканируйте код"/><b>{selected.length} выбрано</b>{scanMessage&&<em className={`is-${scanMessage.tone}`}>{scanMessage.text}</em>}</div>{kind==="issue"&&requirements.length>0&&<div className="bo-kit-check"><div><strong>Комплектность</strong><span>Система проверит её при проведении документа</span></div>{requirements.map(m=>{const serial=m.trackingMode==="serial",included=serial&&selected.some(id=>units.find(u=>u.id===id)?.modelId===m.id);return <span key={m.id} className={included?"is-ready":"is-missing"}>{included?"✓ ":"! "}{m.name}{!serial?" · выдать в разделе «Кабели»":""}</span>})}<button onClick={addSerialRequirements}>Добавить доступные серийные позиции</button></div>}<table className="bo-table"><thead><tr><th></th><th>Единица</th><th>Статус</th></tr></thead><tbody>{eligible.map((unit) => <tr key={unit.id}><td><input type={kind === "transfer" ? "radio" : "checkbox"} checked={selected.includes(unit.id)} onChange={() => setSelected((current) => kind === "transfer" ? [unit.id] : current.includes(unit.id) ? current.filter((id) => id !== unit.id) : [...current, unit.id])} /></td><td>{unit.assetTag}</td><td>{statusLabel[unit.status]}</td></tr>)}</tbody></table></section><DocumentJournal data={data} rows={docs} post={id=>commands.postDocument.mutate(id)} reverse={id=>commands.reverseDocument.mutate(id)} canManage={can("warehouse.issue","warehouse.catalog.manage")}/></>;
}

function DocumentJournal({data,rows,post,reverse,canManage}:{data:Data;rows:Operations.OperationDocumentDTO[];post:(id:string)=>void;reverse:(id:string)=>void;canManage:boolean}){const [selected,setSelected]=useState<Operations.OperationDocumentDTO|null>(null);const people=new Map((data.people.data??[]).map(x=>[x.id,x.displayName]));const columns:RegisterColumn<Operations.OperationDocumentDTO>[]=[{id:"number",label:"Номер",value:r=>r.number},{id:"kind",label:"Тип",value:r=>({issue:"Выдача",return:"Возврат",transfer:"Перемещение",inventory:"Инвентаризация"}[r.kind])},{id:"status",label:"Статус",value:r=>({draft:"Черновик",posted:"Проведён",reversed:"Сторнирован"}[r.status])},{id:"created",label:"Создан",value:r=>dt(r.createdAt)},{id:"owner",label:"Ответственный",value:r=>people.get(r.createdBy)??r.createdBy.slice(0,8)},{id:"action",label:"Действие",value:r=>r.status,render:r=>canManage?r.status==="draft"?<button onClick={e=>{e.stopPropagation();if(confirm(`Провести документ ${r.number}?`))post(r.id)}}>Провести</button>:r.status==="posted"?<button onClick={e=>{e.stopPropagation();if(confirm(`Сторнировать документ ${r.number}?`))reverse(r.id)}}>Сторнировать</button>:"—":"—"}];return <div className={selected?"bo-split":""}><Register id="operation-documents" rows={rows} columns={columns} rowKey={r=>r.id} onOpen={setSelected}/>{selected&&<DocumentPreview document={selected} data={data} close={()=>setSelected(null)} />}</div>;}

function DocumentPreview({document:d,data,close}:{document:Operations.OperationDocumentDTO;data:Data;close:()=>void}) { const units=new Map((data.units.data??[]).map(x=>[x.id,x.assetTag])),projects=new Map((data.projects.data??[]).map(x=>[x.id,x.name])),warehouses=new Map((data.warehouses.data??[]).map(x=>[x.id,x.name])),people=new Map((data.people.data??[]).map(x=>[x.id,x.displayName])); const p=d.payload; const lines=p.kind==="issue"?p.unitIds.map(id=>units.get(id)??id):p.kind==="return"?p.expectedUnitIds.map(id=>`${units.get(id)??id}${p.returnedUnitIds.includes(id)?" · возвращено":" · не возвращено"}`):p.kind==="transfer"?[`${units.get(p.unitId)??p.unitId} → ${warehouses.get(p.warehouseId)??p.warehouseId}`]:p.lines.map(x=>`${units.get(x.unitId)??x.unitId} · ${x.present?"найдено":"не найдено"}`); const projectId="projectId" in p?p.projectId:null; return <aside className="bo-panel bo-peek bo-unit-card"><div className="bo-panel__head"><span>Документ {d.number}</span><button aria-label="Закрыть карточку" onClick={close}>×</button></div><dl className="bo-details"><dt>Статус</dt><dd>{{draft:"Черновик",posted:"Проведён",reversed:"Сторнирован"}[d.status]}</dd><dt>Ответственный</dt><dd>{people.get(d.createdBy)??d.createdBy}</dd><dt>Создан</dt><dd>{dt(d.createdAt)}</dd><dt>Проведён</dt><dd>{dt(d.postedAt)}</dd>{projectId&&<><dt>Проект</dt><dd>{projects.get(projectId)??projectId}</dd></>}<dt>Комментарий</dt><dd>{p.note??"—"}</dd></dl><section className="bo-card-section"><h3>Состав</h3><ol className="bo-doc-lines">{lines.map((line,i)=><li key={`${line}-${i}`}>{line}</li>)}</ol></section><button className="bo-primary" onClick={()=>window.print()}>Печать / PDF</button></aside>; }

function InventoryWorkspace({ data,commands,can }: { data: Data;commands:Commands;can:(...permissions:Permission[])=>boolean }) { const units = data.units.data ?? []; const [missing,setMissing]=useState<string[]>([]),[note,setNote]=useState(""),[scan,setScan]=useState(""),[scanning,setScanning]=useState(false),[message,setMessage]=useState(""); const byStatus = Object.entries(Object.groupBy(units, (unit) => unit.status)); const scanFound=()=>{const code=scan.trim().toLocaleLowerCase(),unit=units.find(u=>u.assetTag.toLocaleLowerCase()===code||(u.serial??"").toLocaleLowerCase()===code);if(!unit)setMessage(`Код «${scan.trim()}» не найден`);else if(!missing.includes(unit.id))setMessage(`${unit.assetTag} уже отмечено найденным`);else{setMissing(x=>x.filter(id=>id!==unit.id));setMessage(`${unit.assetTag} найдено`);}setScan("");}; return <><section className="bo-panel"><div className="bo-document-head"><div><div className="bo-eyebrow">Инвентаризационная ведомость · черновик</div><h2>Фактические остатки</h2></div><button className="bo-primary" disabled={!missing.length||!can("warehouse.catalog.manage","warehouse.issue")} onClick={()=>commands.createDocument.mutate({kind:"inventory",lines:units.map(unit=>({unitId:unit.id,present:!missing.includes(unit.id)})),note:note.trim()||null},{onSuccess:()=>{setMissing([]);setNote("");setScanning(false);}})}>Сохранить черновик</button></div><div className="bo-doc-fields"><label>Комментарий<input value={note} onChange={e=>setNote(e.target.value)} placeholder="Номер ведомости или примечание" /></label></div><div className="bo-scanner"><button onClick={()=>{setScanning(true);setMissing(units.map(u=>u.id));setMessage("Сканируйте найденные единицы");}}>Начать сканирование</button><input aria-label="Сканер инвентаризации" disabled={!scanning} value={scan} onChange={e=>setScan(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"&&scan.trim())scanFound();}} placeholder="Инвентарный или серийный номер"/><b>{units.length-missing.length} / {units.length} найдено</b>{message&&<em>{message}</em>}</div><table className="bo-table"><thead><tr><th>Не найдено</th><th>Единица</th><th>Ожидаемый статус</th></tr></thead><tbody>{units.map(unit=><tr key={unit.id}><td><input type="checkbox" checked={missing.includes(unit.id)} onChange={()=>setMissing(current=>current.includes(unit.id)?current.filter(id=>id!==unit.id):[...current,unit.id])}/></td><td>{unit.assetTag}</td><td>{statusLabel[unit.status]??unit.status}</td></tr>)}</tbody></table><div className="bo-grid bo-grid--accounts">{byStatus.map(([status, rows]) => <div className="bo-panel" key={status}><span>{statusLabel[status] ?? status}</span><strong>{rows?.length ?? 0}</strong></div>)}</div><p className="bo-note">Проведение помечает отсутствующие единицы как утерянные и создаёт Problems; сторно восстанавливает прежние статусы. Журнал остаётся неизменяемым.</p></section><DocumentJournal data={data} rows={(data.documents.data??[]).filter(row=>row.kind==="inventory")} post={id=>commands.postDocument.mutate(id)} reverse={id=>commands.reverseDocument.mutate(id)} canManage={can("warehouse.catalog.manage","warehouse.issue")}/></>; }

function MovementWorkspace({ data, query }: { data: Data; query: string }) { const units = new Map((data.units.data ?? []).map((row) => [row.id, row.assetTag])); const projects = new Map((data.projects.data ?? []).map((row) => [row.id, row.name])); const warehouses = new Map((data.warehouses.data ?? []).map((row) => [row.id, row.name])); const rows = (data.journal.data ?? []).filter((r) => !query || JSON.stringify(r).toLowerCase().includes(query.toLowerCase())); const columns: RegisterColumn<Equipment.JournalEntryDTO>[] = [{ id: "at", label: "Время", value: (r) => dt(r.at) }, { id: "object", label: "Объект", value: (r) => units.get(r.unitId ?? "") ?? r.modelId ?? "—" }, { id: "action", label: "Действие", value: (r) => r.action }, { id: "project", label: "Проект", value: (r) => projects.get(r.projectId ?? "") ?? "—" }, { id: "warehouse", label: "Склад", value: (r) => warehouses.get(r.warehouseId ?? r.toWarehouseId ?? "") ?? "—" }, { id: "qty", label: "Количество", value: (r) => r.qty ?? 1, align: "right" }]; return <Register id="movement" rows={rows} columns={columns} rowKey={(row) => row.id} />; }

function PeopleWorkspace({ data,commands,can,query }: { data: Data;commands:Commands;can:(...permissions:Permission[])=>boolean;query:string }) { const [creating,setCreating]=useState(false),[name,setName]=useState(""),[email,setEmail]=useState(""),[roleId,setRoleId]=useState(""),[temporary,setTemporary]=useState<{name:string;password:string}|null>(null); const roles=data.roles.data??[], effectiveRole=roleId||roles[0]?.id||""; const columns: RegisterColumn<People.UserDTO>[] = [{ id: "name", label: "Сотрудник", value: (r) => r.displayName }, { id: "role", label: "Роль", value: (r) => r.roleName }, { id: "email", label: "Email", value: (r) => r.email ?? "—" }, { id: "rate", label: "Ставка", value: (r) => r.hourlyRateEUR ?? 0, render: (r) => r.hourlyRateEUR == null ? "—" : money(r.hourlyRateEUR) }, { id: "status", label: "Статус", value: (r) => r.active ? "Активен" : "Архив" }]; return <>{temporary&&<section className="bo-panel bo-success"><strong>Временный пароль для {temporary.name}</strong><code>{temporary.password}</code><span>Скопируйте сейчас: после закрытия он больше не показывается.</span><button onClick={()=>setTemporary(null)}>Скрыть</button></section>}{creating&&<section className="bo-panel bo-inline-form"><label>Имя<input value={name} onChange={e=>setName(e.target.value)} /></label><label>Email<input type="email" value={email} onChange={e=>setEmail(e.target.value)} /></label><label>Роль<select value={effectiveRole} onChange={e=>setRoleId(e.target.value)}>{roles.map(r=><option key={r.id} value={r.id}>{r.name}</option>)}</select></label><button className="bo-primary" disabled={!name.trim()||!email.trim()||!effectiveRole||commands.createPerson.isPending} onClick={()=>commands.createPerson.mutate({displayName:name.trim(),email:email.trim(),roleId:effectiveRole},{onSuccess:r=>{if(r.temporaryPassword)setTemporary({name:r.user.displayName,password:r.temporaryPassword});setCreating(false);setName("");setEmail("");}})}>Создать сотрудника</button><button onClick={()=>setCreating(false)}>Отмена</button></section>}<Register id="people" rows={data.people.data ?? []} columns={columns} rowKey={(row) => row.id} externalQuery={query} toolbar={can("people.manage")?<button className="bo-primary" onClick={()=>setCreating(true)}>Новый сотрудник</button>:null} /></>; }
function ContractorsWorkspace({ data,commands,can,query }: { data: Data;commands:Commands;can:(...permissions:Permission[])=>boolean;query:string }) { const [creating,setCreating]=useState(false),[name,setName]=useState(""),[contacts,setContacts]=useState(""); const items = data.contractorItems.data ?? []; const columns: RegisterColumn<Equipment.ContractorDTO>[] = [{ id: "name", label: "Подрядчик", value: (r) => r.name }, { id: "contacts", label: "Контакты", value: (r) => r.contacts ?? "—" }, { id: "open", label: "Открытых позиций", value: (r) => items.filter((i) => i.contractorId === r.id).length, align: "right" }, { id: "debt", label: "Себестоимость", value: (r) => items.filter((i) => i.contractorId === r.id).reduce((sum, i) => sum + i.costEUR * i.qty, 0), render: (r) => money(items.filter((i) => i.contractorId === r.id).reduce((sum, i) => sum + i.costEUR * i.qty, 0)), align: "right" }]; return <>{creating&&<section className="bo-panel bo-inline-form"><label>Название<input value={name} onChange={e=>setName(e.target.value)} /></label><label>Контакты<input value={contacts} onChange={e=>setContacts(e.target.value)} /></label><button className="bo-primary" disabled={!name.trim()||commands.createContractor.isPending} onClick={()=>commands.createContractor.mutate({name:name.trim(),contacts:contacts.trim()||null},{onSuccess:()=>{setCreating(false);setName("");setContacts("");}})}>Создать подрядчика</button><button onClick={()=>setCreating(false)}>Отмена</button></section>}<Register id="contractors" rows={data.contractors.data ?? []} columns={columns} rowKey={(row) => row.id} externalQuery={query} toolbar={can("warehouse.catalog.manage")?<button className="bo-primary" onClick={()=>setCreating(true)}>Новый подрядчик</button>:null} /></>; }

function FinanceWorkspace({ data, commands, can }: { data: Data; commands: Commands; can: (...permissions: Permission[]) => boolean }) {
  const [creating,setCreating]=useState(false); const [accountId,setAccountId]=useState(""); const [kind,setKind]=useState<Finance.TxKind>("income"); const [amount,setAmount]=useState(""); const [note,setNote]=useState("");
  const accounts = new Map((data.accounts.data ?? []).map((r) => [r.id, r.name])); const columns: RegisterColumn<Finance.TransactionDTO>[] = [{ id: "at", label: "Дата", value: (r) => dt(r.createdAt) }, { id: "account", label: "Счёт", value: (r) => accounts.get(r.accountId) ?? "—" }, { id: "kind", label: "Тип", value: (r) => r.kind === "income" ? "Доход" : "Расход" }, { id: "category", label: "Категория", value: (r) => r.category }, { id: "amount", label: "Сумма EUR", value: (r) => r.amountEUR, render: (r) => money(r.amountEUR), align: "right" }, { id: "note", label: "Комментарий", value: (r) => r.note ?? "—" }];
  const account=data.accounts.data?.find((row)=>row.id===accountId);
  return <><div className="bo-grid bo-grid--accounts">{(data.accounts.data ?? []).map((row) => <div className="bo-panel" key={row.id}><span>{row.name}</span><strong>{row.balance} {row.currency}</strong></div>)}</div>{creating&&<section className="bo-panel bo-inline-form"><label>Счёт<select value={accountId} onChange={(e)=>setAccountId(e.target.value)}><option value="">Выберите счёт</option>{(data.accounts.data??[]).map((row)=><option key={row.id} value={row.id}>{row.name}</option>)}</select></label><label>Тип<select value={kind} onChange={(e)=>setKind(e.target.value as Finance.TxKind)}><option value="income">Доход</option><option value="expense">Расход</option></select></label><label>Сумма<input type="number" min="0.01" step="0.01" value={amount} onChange={(e)=>setAmount(e.target.value)}/></label><label>Комментарий<input value={note} onChange={(e)=>setNote(e.target.value)}/></label><button className="bo-primary" disabled={!account||Number(amount)<=0} onClick={()=>account&&commands.createTransaction.mutate({accountId:account.id,kind,category:"other",amount:Number(amount),currency:account.currency,note:note||null},{onSuccess:()=>{setCreating(false);setAmount("");setNote("");}})}>Провести</button></section>}<Register id="finance" rows={data.transactions.data ?? []} columns={columns} rowKey={(row) => row.id} toolbar={can("finance.manage") ? <button className="bo-primary" onClick={() => setCreating(true)}>Новая транзакция</button> : null} /></>;
}

function ProblemsWorkspace({ data, commands, can }: { data: Data; commands: Commands; can: (...permissions: Permission[]) => boolean }) { const columns: RegisterColumn<Problem>[] = [{ id: "severity", label: "Приоритет", value: (r) => r.severity }, { id: "title", label: "Проблема", value: (r) => r.title }, { id: "detail", label: "Описание", value: (r) => r.detail }, { id: "created", label: "Создана", value: (r) => dt(r.createdAt) }, { id: "state", label: "Состояние", value: (r) => r.resolved ? "Решена" : "Открыта", render: (r) => !r.resolved && can("warehouse.issue") ? <button onClick={(e) => { e.stopPropagation(); commands.resolveProblem.mutate(r.id); }}>Решить</button> : r.resolved ? "Решена" : "Открыта" }]; return <Register id="problems" rows={data.problems.data ?? []} columns={columns} rowKey={(row) => row.id} />; }

function ReportBuilder({ data }: { data: Data }) { const [dimension, setDimension] = useState<"status" | "warehouse">("status"); const units = data.units.data ?? []; const warehouses = new Map((data.warehouses.data ?? []).map((w) => [w.id, w.name])); const groups = Object.entries(Object.groupBy(units, (unit) => dimension === "status" ? statusLabel[unit.status] ?? unit.status : warehouses.get(unit.warehouseId ?? "") ?? "Без склада")); return <section className="bo-panel"><div className="bo-toolbar"><div><div className="bo-eyebrow">Конструктор отчёта</div><h2>Оборудование</h2></div><label>Строки <select value={dimension} onChange={(e) => setDimension(e.target.value as typeof dimension)}><option value="status">Статус</option><option value="warehouse">Склад</option></select></label></div><table className="bo-table"><thead><tr><th>{dimension === "status" ? "Статус" : "Склад"}</th><th>Количество</th><th>Стоимость</th></tr></thead><tbody>{groups.map(([name, rows]) => <tr key={name}><td>{name}</td><td>{rows?.length ?? 0}</td><td>{money((rows ?? []).reduce((sum, unit) => sum + (data.models.data?.find((model) => model.id === unit.modelId)?.unitCostEUR ?? 0), 0))}</td></tr>)}</tbody></table></section>; }

function AuditWorkspace({data,query}:{data:Data;query:string}) { const people=new Map((data.people.data??[]).map(x=>[x.id,x.displayName])); const method:Record<string,string>={POST:"Создание/действие",PATCH:"Изменение",PUT:"Обновление",DELETE:"Удаление"}; const columns:RegisterColumn<Audit.AuditEntryDTO>[]=[{id:"at",label:"Время",value:r=>dt(r.createdAt)},{id:"actor",label:"Пользователь",value:r=>r.actorId?people.get(r.actorId)??r.actorId.slice(0,8):"Не авторизован"},{id:"method",label:"Действие",value:r=>method[r.method]??r.method},{id:"path",label:"Объект API",value:r=>r.path},{id:"status",label:"Результат",value:r=>r.statusCode,render:r=>r.statusCode<400?"Успешно":`Ошибка ${r.statusCode}`}]; return <Register id="audit" rows={data.audit.data??[]} columns={columns} rowKey={r=>r.id} externalQuery={query} />; }

function PermissionsWorkspace({ data, commands, can }: { data: Data; commands: Commands; can: (...permissions: Permission[]) => boolean }) { const [draft, setDraft] = useState<Record<string, Permission[]>>({}); const roles = data.roles.data ?? []; const perms = PERMISSIONS.map((p) => p.key); const toggle = (role: People.RoleDTO, permission: Permission) => setDraft((current) => { const values = current[role.id] ?? role.permissions; return { ...current, [role.id]: values.includes(permission) ? values.filter((p) => p !== permission) : [...values, permission] }; }); return <section className="bo-panel"><div className="bo-toolbar"><div><div className="bo-eyebrow">Администрирование</div><h2>Матрица прав</h2></div><button className="bo-primary" disabled={!can("roles.manage")} onClick={() => Object.entries(draft).forEach(([id, permissions]) => commands.updateRole.mutate({ id, input: { permissions } }))}>Сохранить изменения</button></div><div className="bo-table-wrap"><table className="bo-table bo-table--matrix"><thead><tr><th>Код права</th>{roles.map((role) => <th key={role.id}>{role.name}</th>)}</tr></thead><tbody>{perms.map((permission) => <tr key={permission}><td className="bo-mono">{permission}</td>{roles.map((role) => { const checked = (draft[role.id] ?? role.permissions).includes(permission); return <td key={role.id}><button className={`bo-permission ${checked ? "bo-permission--full" : "bo-permission--none"}`} disabled={role.isOwner || !can("roles.manage")} onClick={() => toggle(role, permission)}>{checked ? "Да" : "Нет"}</button></td>; })}</tr>)}</tbody></table></div></section>; }
